var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"날 불렀다면서? 들어갈게.","JPN":"私を呼んだ？　入るよ。","ENG":"You wanted to see me? I'm coming in.","TWN":"你找我嗎？那我進來囉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"괜찮아. 이미 각오는 되었으니까.","JPN":"大丈夫。すでに覚悟はできていたから。","ENG":"It's fine. I've already made up my mind.","TWN":"沒關係，我已做好心理準備。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"코핀컴퍼니 창설 이후 최대 임무에 투입되는 거잖아?","JPN":"コフィンカンパニー創設以来の最大の任務に投入されるんじゃない？","ENG":"I'm being assigned to the biggest mission since Coffin Company was founded, right?","TWN":"這是自科芬公司成立以來最大的任務，對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"대단한 작전이 진행될 텐데 단둘 뿐이서 회의를 진행해도 괜찮은 거야?","JPN":"大がかりな作戦進行になると思うけど、二人きりで会議を進めても大丈夫？","ENG":"It's such a big operation, but are you sure you want to discuss it with just me?","TWN":"這麼大的作戰計畫，只有我們兩個人開會真的沒問題嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"엇… 아니라고? 그, 그렇다면 날 따로 부른 이유가 뭐지?","JPN":"あ……違うの？　そ、それなら私をわざわざ呼んだ理由はなに？","ENG":"Huh...? That's not why you called? Th-then why did you?","TWN":"嗯…不是這件事嗎？那，那你單獨找我的理由是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"종신계약…? 아… 그런 거였구나.","JPN":"終身契約……？　あ……そういうことだったのか。","ENG":"A lifetime contract...? Oh... So that's why.","TWN":"終身契約…？喔…原來如此。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"부를 때 미리 말해주었으면 좋았을 텐데. 갑자기 오라고 하니까 오해했잖아.","JPN":"呼び出す前に言ってくれたら良かったのに。急に来いと言うから誤解した。","ENG":"It would've been better if you gave me a heads up. I was startled when you suddenly wanted to see me.","TWN":"怎麼不早說？突然把我找來，害我誤會。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"음….","JPN":"うーん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"엇, 꺼려지면 하지 않아도 좋다고? 아, 아냐. 내가 언제 싫다고 했어?","JPN":"あ、嫌ならやらなくてもいいって？　いや、私がいつ嫌だって言った？","ENG":"Oh? I don't have to do it if I don't want to? N-no. When did I say, I didn't want to?","TWN":"呃？我不願意的話也沒關係？我沒有，我又沒說我不願意？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그냥… 사샤와 함께 있었다면 더 좋았을거라 생각하고 있었어.","JPN":"ただ……サシャと一緒にいれたら、もっといいのにと思っていたんだ。","ENG":"It's just... I was thinking how better it would be if Sasha was with me.","TWN":"我只是…希望這種時候莎夏也在就好了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"이곳은 그토록 원했던 평범한 친구들, 재미있는 만화, 따뜻한 생활 전부 있으니까.","JPN":"ここにはあれほど望んだ平凡な友達、面白いマンガ、温かい生活の全てがあるから。","ENG":"This place has everything we wanted. Friends, funny cartoons, and a comfy life.","TWN":"這裡有我一直想要的朋友、有趣的漫畫和溫暖的生活。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"행복하긴 하지만, 조금은 씁쓸한 마음이 들긴 해.","JPN":"幸せではあるけど、少しほろ苦い気もする。","ENG":"I am happy, but I also feel a little sad.","TWN":"雖然很幸福，但心裡還是有點難過。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"우리가 지켜내지 않으면 지금 이 모든 것도 결국엔 잃게 되겠지.","JPN":"私たちが守らなかったら、結局は今あるすべてを失うことになるでしょ。","ENG":"If we don't protect them, we'll lose everything we have.","TWN":"若我們不去守護這些，現在這一切最終也都會失去吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"좋았어. 사인할게.","JPN":"いいよ、サインする。","ENG":"Sure, I'll sign it.","TWN":"好，我願意。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"더 이상 사람들이 상처받고, 망가지는 모습은 보고 싶지 않아.","JPN":"これ以上、人々が傷ついて壊れる姿を見たくない。","ENG":"I don't want to see anyone get hurt or broken.","TWN":"我不想再看到大家受傷和崩潰的樣子。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"반드시… 지켜내고 말겠어.","JPN":"必ず……守ってみせる。","ENG":"I'll... protect them, no matter what.","TWN":"我一定…會守護這一切。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"세상을 위해… 그리고 사샤를 위해.","JPN":"この世界のために……そしてサシャのために。","ENG":"For the world... and for Sasha.","TWN":"為了世界…也為了莎夏。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"자. 사인한 거 확인했지? 이제 난 당신을 위해 계속해서 힘이 되어주겠어.","JPN":"サインしたの確認したね？　これから私はあなたのためにずっと力になってあげる。","ENG":"Here. Did you check? Now, I'll continue to be strong for you.","TWN":"簽名你看過沒問題吧？現在起，我會持續成為你的助力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"그러니까 당신도 언제나 나에게 힘이 되어줘야 해. 알았지?","JPN":"だからあなたも私にいつでも力を貸してね。いい？","ENG":"So you also must always be strong for me too, okay?","TWN":"你也要成為我的助力，知道嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_NULL","text":{"KOREA":"혼자서는 세상을 지킬 수 없는 법이니까. 후훗.","JPN":"独りではこの世界を守ることなんてできないから。ふふっ。","ENG":"Because I can't protect the world on my own. Haha.","TWN":"畢竟一個人是無法守護世界的，呵呵。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};